const envelope = $json || {};
const data = envelope.data || {};
const order = data.order || {};
const customer = order.customer || {};

return [{
  json: {
    orderId: order.orderId || 'N/A',
    previousStatus: data.previousStatus || null,
    status: order.status || 'pending',
    reviewedAt: Number(order.reviewedAt || Date.now()),
    customerName: customer.name || 'Client',
    phone: customer.phone || 'N/A',
    total: Number(order.total || 0),
    reference: order.payment?.referencePaiement || order.payment?.txId || 'N/A'
  }
}];

const statusInfo = {
  pending: '[WAIT] En attente',
  approved: '[OK] Approuvee',
  rejected: '[NO] Rejetee'
};

const toStatus = statusInfo[$json.status] || $json.status;
const fromStatus = $json.previousStatus ? (statusInfo[$json.previousStatus] || $json.previousStatus) : 'inconnu';
const total = Number($json.total || 0).toLocaleString('fr-FR');
const reviewedAt = new Date($json.reviewedAt || Date.now()).toLocaleString('fr-FR');

const lines = [
  'Mise a jour commande Librairie YO',
  `Commande: #${$json.orderId}`,
  `De: ${fromStatus}`,
  `Vers: ${toStatus}`,
  `Client: ${$json.customerName}`,
  `Telephone: +${$json.phone}`,
  `Reference paiement: ${$json.reference}`,
  `Total: ${total} GNF`,
  `Traitee le: ${reviewedAt}`
];

return [{ json: { text: lines.join('\n') } }];
